const CFG = {
  QUERY: '(AI OR \'large language model\' OR LLM OR 生成式) AND (research OR benchmark OR safety OR eval OR regulation)',
  LANGUAGE: 'en',
  FROM_DAYS: 7,
  MAX_ARTICLES: 20,
  TAKE_TOP: 30,
  OPENAI_CHAT: 'gpt-4o-mini',
  OPENAI_IMAGE: 'gpt-image-1',
  COVER_SIZE: '1024x576',
  BODY_SIZE: '1024x1024',
  BRAND: {
    palette: ['#0F172A','#22D3EE','#A78BFA'],
    style: 'editorial illustration, semi-flat, clean, minimal, soft lighting',
    negatives: 'text, watermark, logo, brand, people, realistic faces, hands, busy background'
  }
};
CFG.FROM_ISO = new Date(Date.now() - CFG.FROM_DAYS*24*60*60*1000).toISOString();
return [{json: CFG}];

const cfgItem = $items('SetConfig', 0, 0) || { json: {} };
const cfg = cfgItem.json || {};
const takeTop = Number(cfg.TAKE_TOP || 30);
const articles = (items[0].json.articles || []).map(a => ({
  title: a.title, url: a.url, description: a.description || '',
  content: a.content || '', author: a.author || '',
  source: (a.source && a.source.name) || '', publishedAt: a.publishedAt || ''
})).filter(a => a.title && a.url);
function host(u){ 
  try { 
    return new URL(u).hostname.replace(/^www\./,''); 
  } catch { 
    return ''; 
  } 
}
function hours(iso){ 
  return Math.max(1,(Date.now()-new Date(iso||Date.now()).getTime())/36e5); 
}
function recency(h){ 
  if(h<=24) return 20; 
  if(h<=48) return 14; 
  if(h<=168) return 9; 
  return 3; 
}
function depth(text){ 
  const l=text.length; 
  let s=l>8000?18:l>4000?14:l>1500?10:l>800?7:4;
  if(/arxiv|doi|github|sec\./i.test(text)) 
    s+=2; 
  return Math.min(20,s); 
}
function srcScore(hn){ 
  return /arxiv|nature|sciencedirect|reuters|bloomberg|ft|nytimes|semianalysis|alignmentforum|lesswrong|theverge|techcrunch/i.test(hn)?30:18; 
}
function originality(t){ 
  return /exclusive|interview|whitepaper|benchmark|replicate|ablations?/i.test(t)?8:4; }
function author(a){ 
  return a ? (a.includes(' ')?12:8) : 3; 
}
function score(a){
  const txt = `${a.title}\n${a.description}\n${a.content}`;
  return Math.round(0.35*srcScore(host(a.url)) + 0.20*recency(hours(a.publishedAt)) + 0.20*depth(txt) + 0.10*originality(txt) + 0.15*author(a.author));
}

const buckets = new Map();

for (const a of articles){
  const key=(a.title||'').toLowerCase().replace(/[^\w\s]/g,' ').replace(/\s+/g,' ').trim();
  const s=score(a);
  const j={...a, QualityScore:s, host:host(a.url)};
  if(!buckets.has(key)) 
    buckets.set(key,[]);
  buckets.get(key).push(j);
}
let kept=[];
for (const [,group] of buckets){ 
  group.sort((x,y)=>y.QualityScore-x.QualityScore); 
  kept.push(group[0]); 
}

kept.sort((a,b)=>b.QualityScore-a.QualityScore);

if (!kept.length) {
  throw new Error('No NewsAPI candidates returned for current configuration');
}
const takeCount = Math.min(takeTop, kept.length);
kept = kept.slice(0, takeCount);
const primary = kept[0];
const related = kept.slice(1, 4);
return [{json:{primary,related,candidates: kept}}];

const choices = Array.isArray($json.choices) ? $json.choices : [];
function extractText(entry) {
  if (!entry) return '';
    const message = entry.message || {};
  const content = message.content;
  if (Array.isArray(content)) {
    return content.map(part => {
      if (typeof part === 'string') return part;
      if (part && typeof part.text === 'string') return part.text;
      if (part && typeof part.value === 'string') return part.value;
      if (part && typeof part.content === 'string') return part.content;
      if (part && part.content && typeof part.content.text === 'string') 
        return part.content.text;
      return '';
    }).join('');
  }
  if (typeof content === 'string') return content;

  return '';
}
const combined = choices
  .map(extractText)
  .filter(Boolean)
  .join("\\n")
  .trim();
let payload = { markdown: '', prompts: [] };
if (combined) {
  try {
    payload = JSON.parse(combined);
  } catch (error) {
    const match = combined.match(/\\{[\\s\\S]*\\}/);
    if (match) {
      try {
        payload = JSON.parse(match[0]);
      } catch (innerError) {
        payload = { markdown: combined, prompts: [] };
      }
    } else {
      payload = { markdown: combined, prompts: [] };
    }
  }
}
return [{ json: { payload, raw: combined } }];

const cfgItem = $items('SetConfig', 0, 0) || { json: {} };
const cfg = cfgItem.json || {};
const payload = $json.payload || {};
const prompts = Array.isArray(payload.prompts) ? payload.prompts.filter(p => typeof p === 'string' && p.trim()) : [];
if (!prompts.length) {
  throw new Error('LLM response did not provide image prompts');
}
const coverSize = cfg.COVER_SIZE || '1024x576';
const bodySize = cfg.BODY_SIZE || '1024x1024';
const slots = prompts.slice(0, 4).map((prompt, idx) => ({
  role: idx === 0 ? 'cover' : `keypoint${idx}`,
  prompt: prompt.trim(),
  size: idx === 0 ? coverSize : bodySize
}));
return slots.map(slot => ({ json: slot }));

const payload = $('ParseLLMPayload').first().json.payload;
let title = payload.title || '';
let markdown = payload.markdown || '';
const imgs = Array.isArray(items) ? items : [];

// throw new Error(JSON.stringify({ imgsLen: imgs.length, sample: imgs }));

let used = new Array(imgs.length).fill(false);
// 3) 封面处理：取第一张作为封面，优先替换 <!--IMG_COVER-->，没有就前置
const cover = imgs[0]?.json?.url || '';
if (cover) {
  const coverRe = /<!--\s*IMG_COVER\s*-->/i;
  if (coverRe.test(markdown)) {
    markdown = markdown.replace(coverRe, `![封面](${cover})`);
  } else {
    markdown = `![封面](${cover})\n\n` + markdown;
  }
}
used[0] = true;

// 4) 关键点锚点替换：支持 <!--IMG_KP--> 与带编号的 <!--IMG_KP3-->
//    规则：带编号优先按编号用图（1→bodies[0]），不带编号按顺序消耗下一张未使用的图
const kpRe = /<!--\s*IMG_KP(?:\s*(\d+))?\s*-->/gi;

markdown = markdown.replace(kpRe, (_, numStr) => {
  let idx = null;

  if (numStr) {
    // 1-based → 0-based
    const n = parseInt(numStr, 10);
    if (!Number.isNaN(n) && n >= 1) idx = n;
  }

  // 选择图片：
  // - 指定编号且存在 → 用该张
  // - 否则 → 找到下一个未使用的
  let url = null;
  if (idx !== null && imgs[idx]?.json?.url) {
    url = imgs[idx]?.json?.url;
    used[idx] = true;
  } else {
    const next = used.findIndex(u => u === false);
    if (next !== -1 && imgs[next]?.json?.url) {
      url = imgs[next]?.json?.url;
      used[next] = true;
      idx = next;
    }
  }

  // 没图可用，就删除占位（返回空串）
  if (!url) return '';

  const label = `图 ${typeof idx === 'number' ? idx : ''}`.trim();
  return `![${label}](${url})`;
});

// 5) 兜底：还有没用上的图片 → 追加到文末
for (let i = 1; i < imgs.length; i++) {
  if (!used[i] && imgs[i]?.json?.url) {
    markdown += `\n\n![图 ${i + 1}](${imgs[i]?.json?.url})`;
  }
}


