return [{ json: {title:title, markdown: markdown.trim(), _debug: { urlsCount: imgs.length, imgs: imgs, used } } }];

function slugify(s){return (s||'ai-commentary').toLowerCase().replace(/[^a-z0-9\u4e00-\u9fa5]+/g,'-').replace(/^-+|-+$/g,'').slice(0,60)||'ai';}
const assembleItem = $items('AssembleMD',0,0) || { json: {} };

//throw new Error(JSON.stringify({ assembleItem : assembleItem[0].json}));
const markdown = assembleItem[0].json.markdown || '';
const scoreItem = $items('ScoreSelect',0,0) || { json: {} };

//throw new Error(JSON.stringify({ scoreItem : scoreItem[0]}));

const fallbackTitle = scoreItem[0].json.primary ? (scoreItem[0].json.primary.title || 'AI 评论') : 'AI 评论';
const titleMatch = assembleItem[0].json.title || '';
const title = titleMatch ? titleMatch : fallbackTitle;
const d = new Date(); 
const yyyy=d.getFullYear(), mm=String(d.getMonth()+1).padStart(2,'0'), dd=String(d.getDate()).padStart(2,'0');
const n = String(Math.floor(Math.random()*1000)).padStart(3,'0');
const filepath = `${yyyy}-${mm}-${dd}/${n}_${slugify(title)}.md`;
const content = Buffer.from(markdown,'utf8').toString('base64');
const message = `feat(post): ${yyyy}-${mm}-${dd} ${title}`;
return [{json:{filepath, content, message}}];

const imgs = $input.all().map((item) => ({
  url: item.json?.data ? item.json?.data[0]?.url : ''
}));
